            update_last_applied_manifest_dict_from_resp(
                last_applied_manifest[i],
                schema_item,
                resp_item
            )

        # Handle list items recursively    
        elif isinstance(resp_item, list) and isinstance(schema_item, list):
            if not isinstance(last_applied_manifest[i], list):
                last_applied_manifest[i] = []
            update_last_applied_manifest_list_from_resp(
                last_applied_manifest[i],
                schema_item,
                resp_item
            )

        # Handle primitive values
        else:
            last_applied_manifest[i] = resp_item

def update_last_applied_manifest_dict_from_resp(
    last_applied_manifest, observer_schema, response
):
    # Iterate through all fields in observer schema
    for field, value in observer_schema.items():
        # Skip if field doesn't exist in response
        if field not in response:
            continue

        # Initialize field in last_applied_manifest if it doesn't exist
        if field not in last_applied_manifest:
            if isinstance(response[field], dict):
                last_applied_manifest[field] = {}
            elif isinstance(response[field], list):
                last_applied_manifest[field] = []
            else:
                last_applied_manifest[field] = response[field]
                continue

        # Recursively update nested dictionaries
        if isinstance(value, dict) and isinstance(response[field], dict):
            update_last_applied_manifest_dict_from_resp(
                last_applied_manifest[field], value, response[field]
            )
        # Update lists
        elif isinstance(value, list) and isinstance(response[field], list):
            if len(value) > 0 and isinstance(value[0], dict):
                # Handle list of dictionaries
                if len(last_applied_manifest[field]) < len(response[field]):
                    last_applied_manifest[field].extend(
                        [{}] * (len(response[field]) - len(last_applied_manifest[field]))
                    )
                for i in range(len(response[field])):
                    update_last_applied_manifest_dict_from_resp(
                        last_applied_manifest[field][i], value[0], response[field][i]
                    )
            else:
                # Handle simple lists
                last_applied_manifest[field] = response[field]
        else:
            # Update simple values
            last_applied_manifest[field] = response[field]

def generate_default_observer_schema(app):
    default_schema = {}

    # Check if app has manifest spec
    if not hasattr(app, 'spec') or not hasattr(app.spec, 'manifest'):
        return default_schema

    # Iterate through resources in manifest
    for resource in app.spec.manifest:
        # Skip if resource already has custom observer schema
        if resource.get('observer_schema'):
            continue

        # Get resource kind
        kind = resource.get('kind', '')

        # Generate default schema based on resource kind
        if kind == 'Deployment':
            default_schema[resource['metadata']['name']] = {
                'ready': '$.status.readyReplicas == $.spec.replicas'
            }
        elif kind == 'StatefulSet':
            default_schema[resource['metadata']['name']] = {
                'ready': '$.status.readyReplicas == $.spec.replicas'
            }
        elif kind == 'DaemonSet':
            default_schema[resource['metadata']['name']] = {
                'ready': '$.status.numberReady == $.status.desiredNumberScheduled'
            }
        elif kind == 'Pod':
            default_schema[resource['metadata']['name']] = {
                'ready': "$.status.phase in ['Running', 'Succeeded']"
            }
        elif kind == 'Service':
            default_schema[resource['metadata']['name']] = {
                'ready': 'true'
            }
        elif kind == 'PersistentVolumeClaim':
            default_schema[resource['metadata']['name']] = {
                'ready': "$.status.phase == 'Bound'"
            }
        elif kind == 'Job':
            default_schema[resource['metadata']['name']] = {
                'ready': "$.status.succeeded == 1"
            }
        elif kind == 'CronJob':
            default_schema[resource['metadata']['name']] = {
                'ready': 'true'
            }

    return default_schema

