def parse_diaspora_webfinger(document: str) -> Dict:
    """
    डायस्पोरा वेबफिंगर को पार्स करें, जो या तो JSON प्रारूप (नया) में होता है या XRD (पुराना) में।
    """
    import json
    import xml.etree.ElementTree as ET
    from typing import Dict

    # Try parsing as JSON first
    try:
        data = json.loads(document)
        result = {
            'subject': data.get('subject', ''),
            'aliases': data.get('aliases', []),
            'links': []
        }

        # Parse links
        for link in data.get('links', []):
            result['links'].append({
                'rel': link.get('rel', ''),
                'type': link.get('type', ''),
                'href': link.get('href', '')
            })

        return result

    except json.JSONDecodeError:
        # If JSON parsing fails, try XRD format
        try:
            # Remove XML namespace to simplify parsing
            document = document.replace('xmlns="http://docs.oasis-open.org/ns/xri/xrd-1.0"', '')
            root = ET.fromstring(document)

            result = {
                'subject': '',
                'aliases': [],
                'links': []
            }

            # Get subject
            subject = root.find('Subject')
            if subject is not None:
                result['subject'] = subject.text

            # Get aliases
            for alias in root.findall('Alias'):
                if alias.text:
                    result['aliases'].append(alias.text)

            # Get links
            for link in root.findall('Link'):
                link_data = {
                    'rel': link.get('rel', ''),
                    'type': link.get('type', ''),
                    'href': link.get('href', '')
                }
                result['links'].append(link_data)

            return result

        except ET.ParseError:
            raise ValueError("Invalid document format - neither valid JSON nor XRD")

    return {}

def retrieve_diaspora_host_meta(host):
    """
    एक रिमोट डायस्पोरा होस्ट-मेटा डॉक्यूमेंट प्राप्त करें।

    :arg host: वह होस्ट जिससे डेटा प्राप्त करना है 
    :returns: ``XRD`` इंस्टेंस
    """
    import requests
    from xrd import XRD

    # Try HTTPS first
    try:
        url = f"https://{host}/.well-known/host-meta"
        response = requests.get(url)
        if response.status_code == 200:
            return XRD.parse_xrd(response.text)
    except:
        pass

    # Fall back to HTTP if HTTPS fails
    try:
        url = f"http://{host}/.well-known/host-meta"
        response = requests.get(url)
        if response.status_code == 200:
            return XRD.parse_xrd(response.text)
    except:
        pass

    raise Exception(f"Could not retrieve host-meta from {host}")

def send_document(url, data, timeout=10, method="post", *args, **kwargs):
    import requests
    from requests.exceptions import RequestException

    try:
        # Convert method to lowercase
        method = method.lower()

        # Select HTTP method
        if method == "post":
            response = requests.post(url, data=data, timeout=timeout, *args, **kwargs)
        elif method == "put":
            response = requests.put(url, data=data, timeout=timeout, *args, **kwargs)
        elif method == "patch":
            response = requests.patch(url, data=data, timeout=timeout, *args, **kwargs)
        else:
            raise ValueError(f"Unsupported HTTP method: {method}")

        # Force raise for bad status codes
        response.raise_for_status()

        return response.status_code, None

    except RequestException as e:
        # Handle requests library exceptions
        if hasattr(e.response, 'status_code'):
            return e.response.status_code, e
        return None, e

    except Exception as e:
        # Handle any other exceptions
        return None, e

