        # Check if option has required_when condition
        if 'required_when' in option:
            required_when = option['required_when']

            # Get the dependent argument and expected value
            dependent_arg = required_when.get('arg')
            expected_value = required_when.get('value')

            # Check if dependent argument exists in provided args
            if dependent_arg in args:
                actual_value = args[dependent_arg]

                # If actual value matches expected value, this option becomes required
                if actual_value == expected_value:
                    conditionally_required.append(option['name'])

    return conditionally_required

def validate_length_args(self, args):
    """
    दिए गए तर्कों की लंबाई की जाँच करें
    :param args: प्राप्त तर्क।  
    """
    if not args or len(args) == 0:
        raise ValueError("No arguments provided")

    for arg in args:
        if not isinstance(arg, (str, list, tuple, dict)) or len(arg) == 0:
            raise ValueError(f"Invalid argument: {arg}. Arguments must be non-empty strings, lists, tuples or dictionaries")

    return True

def validate_choices_args(self, args):
    """
    चॉइस आर्ग्युमेंट्स का मान उपलब्ध विकल्पों में से एक है या नहीं, इसकी जांच करें।

    :param args: प्राप्त किए गए आर्ग्युमेंट्स।
    """
    for arg_name, arg_value in args.items():
        if hasattr(self, 'choices') and arg_name in self.choices:
            valid_choices = self.choices[arg_name]
            if arg_value not in valid_choices:
                raise ValueError(f"Argument '{arg_name}' must be one of {valid_choices}, got '{arg_value}'")

def validate_min_max_args(self, args):
    """
    जांचें कि आर्ग्युमेंट्स का मान न्यूनतम और अधिकतम मानों के बीच है या नहीं।

    :param args: प्राप्त किए गए आर्ग्युमेंट्स।
    """
    for arg_name, arg_value in args.items():
        if hasattr(self, f'min_{arg_name}') and hasattr(self, f'max_{arg_name}'):
            min_val = getattr(self, f'min_{arg_name}')
            max_val = getattr(self, f'max_{arg_name}')

            if not (min_val <= arg_value <= max_val):
                raise ValueError(f'{arg_name} का मान {min_val} और {max_val} के बीच होना चाहिए')

def create_complex_argumet_type(self, subcommand, type_name, option_name, spec_option):
    """
    जटिल आर्गुमेंट प्रकार (complex argument type) बनाएं

    :param subcommand: कमांड का नाम
    :param type_name: जटिल प्रकार का नाम (complex type name) 
    :param option_name: विकल्प का नाम (option name)
    :param spec_option: विकल्प की विशिष्टताएँ (option's specifications)
    :return: जटिल प्रकार का उदाहरण (complex type instance)
    """
    # Create a new class dynamically for the complex type
    complex_type = type(type_name, (), {})

    # Add validation method
    def validate(self, value):
        if not isinstance(value, str):
            raise ValueError(f"Value for {option_name} must be a string")

        # Apply any specific validation rules from spec_option
        if 'min_length' in spec_option:
            if len(value) < spec_option['min_length']:
                raise ValueError(f"{option_name} must be at least {spec_option['min_length']} characters long")

        if 'max_length' in spec_option:
            if len(value) > spec_option['max_length']:
                raise ValueError(f"{option_name} cannot exceed {spec_option['max_length']} characters")

        if 'pattern' in spec_option:
            import re
            if not re.match(spec_option['pattern'], value):
                raise ValueError(f"{option_name} does not match required pattern {spec_option['pattern']}")

        return value

    # Add string representation method
    def __str__(self):
        return f"Complex argument type for {subcommand}:{option_name}"

    # Add methods to the class
    complex_type.validate = validate
    complex_type.__str__ = __str__

    # Create and return an instance
    return complex_type()

def merge_extra_vars(vars_dict, extra_vars=None):
    """
    ``vars_dict`` को ``extra-vars`` के साथ मर्ज (जोड़ना) करें।

    :param vars_dict: वह डिक्शनरी जिसमें extra-vars को मर्ज करना है 
    :param extra_vars: extra-vars की सूची (लिस्ट)
    """
    if extra_vars is None:
        return vars_dict

    if isinstance(extra_vars, list):
        for var in extra_vars:
            if isinstance(var, dict):
                vars_dict.update(var)
    elif isinstance(extra_vars, dict):
        vars_dict.update(extra_vars)

    return vars_dict

def ansible_playbook(ir_workspace, ir_plugin, playbook_path, verbose=None,
                     extra_vars=None, ansible_args=None):
    """
    'ansible-playbook' CLI को रैप करता है।

    :param ir_workspace: एक Infrared Workspace ऑब्जेक्ट जो सक्रिय वर्कस्पेस को दर्शाता है।
    :param ir_plugin: वर्तमान प्लगइन का एक InfraredPlugin ऑब्जेक्ट।
    :param playbook_path: वह प्लेबुक जिसे निष्पादित करना है।
    :param verbose: Ansible की वर्बोसिटी स्तर।
    :param extra_vars: dict। इसे Ansible को अतिरिक्त वेरिएबल्स (extra-vars) के रूप में पास किया जाता है।
    :param ansible_args: ansible-playbook के तर्कों का एक dict, जिसे सीधे Ansible तक पहुँचाने के लिए उपयोग किया जाता है।
    """
    import os
    import subprocess

    # Base command
    cmd = ['ansible-playbook', playbook_path]

    # Add verbosity if specified
    if verbose:
        if isinstance(verbose, bool):
            cmd.append('-v')
        elif isinstance(verbose, int):
            cmd.append('-' + 'v' * verbose)

    # Add extra vars if provided
    if extra_vars:
        if isinstance(extra_vars, dict):
            for key, value in extra_vars.items():
                cmd.extend(['--extra-vars', f'{key}={value}'])

    # Add inventory file from workspace if it exists
    if hasattr(ir_workspace, 'inventory'):
        cmd.extend(['-i', ir_workspace.inventory])

    # Add any additional Ansible arguments
    if ansible_args:
        if isinstance(ansible_args, dict):
            for key, value in ansible_args.items():
                if len(key) == 1:
                    cmd.append(f'-{key}')
                else:
                    cmd.append(f'--{key}')
                if value is not None:
                    cmd.append(str(value))

    # Execute the command
    try:
        result = subprocess.run(
            cmd,
            check=True,
            stdout=subprocess.PIPE,
            stderr=subprocess.PIPE,
            universal_newlines=True
        )
        return result
    except subprocess.CalledProcessError as e:
        raise Exception(f"Ansible playbook execution failed: {e.stderr}")

def _convert_non_cli_args(self, parser_name, values_dict):
    """
    तर्कों को सही प्रकारों में परिवर्तित करता है और values_dict पैरामीटर को संशोधित करता है।

    डिफ़ॉल्ट रूप से, सभी मान स्ट्रिंग्स के रूप में होते हैं।

    :param parser_name: कमांड का नाम, जैसे main, virsh, ospd, आदि।
    :param values_dict: तर्कों के साथ डिक्शनरी।
    """
    # Get parser configuration for this command
    parser_dict = self.parser_dict.get(parser_name, {})

    # Iterate through all arguments in values_dict
    for arg_name, value in values_dict.items():
        # Skip if value is None
        if value is None:
            continue

        # Get argument type from parser configuration
        arg_type = parser_dict.get(arg_name, {}).get('type', str)

        try:
            # Convert boolean strings
            if arg_type == bool:
                if isinstance(value, str):
                    value = value.lower()
                    if value in ('true', 't', 'yes', 'y', '1'):
                        values_dict[arg_name] = True
                    elif value in ('false', 'f', 'no', 'n', '0'):
                        values_dict[arg_name] = False

            # Convert numeric types        
            elif arg_type in (int, float):
                values_dict[arg_name] = arg_type(value)

            # Convert lists
            elif arg_type == list:
                if isinstance(value, str):
                    values_dict[arg_name] = value.split(',')

        except (ValueError, TypeError):
            # Keep original value if conversion fails
            continue

    return values_dict

def get_plugin_spec_flatten_dict(plugin_dir):
    """
    प्लगइन स्पेसिफिकेशन से एक फ्लैट डिक्शनरी बनाता है।

    :param plugin_dir: प्लगइन की डायरेक्टरी का पथ 
    :return: एक फ्लैट डिक्शनरी जो प्लगइन की प्रॉपर्टीज़ को समाहित करती है
    """
    flattened_dict = {}

    try:
        # Read and parse plugin specification file
        spec_file = os.path.join(plugin_dir, 'plugin.json')
        with open(spec_file, 'r', encoding='utf-8') as f:
            spec = json.load(f)

        def flatten(d, parent_key=''):
            for key, value in d.items():
                new_key = f"{parent_key}.{key}" if parent_key else key

                if isinstance(value, dict):
                    flatten(value, new_key)
                else:
                    flattened_dict[new_key] = value

        flatten(spec)

    except FileNotFoundError:
        print(f"Plugin specification file not found in {plugin_dir}")
    except json.JSONDecodeError:
        print(f"Invalid JSON format in plugin specification file")
    except Exception as e:
        print(f"Error processing plugin specification: {str(e)}")

    return flattened_dict

